  "verses": [
    {
      "n": 6,
      "column": "left",
      "text": "Tadeht athildeja Elijus /\nBarakcēta Dehls tas Busite-\nis/ nn fazzija: Es efmu jauns/\net juhs effat wezzi/ tapehz ef-\nnu es pakavejees/ nn jbihjajees\nmannu Sapraischann jums pa-\nahdiht.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Es fazziju: Laid tee Gad-\ni runna/ nn to Gaddu Wai-\nnuns lai to Gudribu iſtahſta.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Teefcham/ tas Gars irr\nekſch Zilwekeem/ nn ta Dwa-\ncha ta Wiſfuwarrena padarra\nchs gudrus.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Tee leeli Laudis ne irr tee\nundraki/ nn tee Wezzajee to\nceefit ne proht.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Tadeht gribbu es run-\naht/ klaufajt manni/ es arri fa-\nvu Sapratshann parahdifchu.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Rangi/ es efmu us juh-\neem Wahrdeem gaidijs/ es ef-\nnu us juhsfu gudru Prahtu us-\nlauſijs/ arrig juhs to ihstenu\nWallohu buhtut ismeklejschi.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Rad es juhs nu efmu weh-\na lizzis/ rangi/ tad irr ne weens/\nas Ijabu buhtu pabrleezinajs/\nas no jums us winna Wahr-\neem atbildetu.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Ka juhs jachu ne fakat:\nNebs effam to Gudribu atrad-\nuscht/ tas STIPRAJS\nDEEWS winnu (zaur man-\ni) novabrehs/ un ne Zilweks.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Prett man wiꞥſch ne irr\ne kahdu Wallohu zehlis/ es arri\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Tee irr isbeedeti/ tee ne\nwarr wairs athildeht/ teem\ntruhfzt Waliodas.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Es tad efmu gaidijs/ bet\ntee ne runna/ jo tee stahw kluf-\ntu/ nn wairs ne atbild.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Es favvu Teefu arri at-\nbildeſchu/ es arri favvu Sapra-\nschann parahdifchu.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Jo es efmu tik pils Wahr-\ndu/ ka ta Dwacha mannu\nWehderu speesch.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Redſi/ mans Wehders\nirr ka tas jauns Wihs/ kas at-\nwehru ne stahw/ wiꞥſch buhtu\nta patt ka jaunt Ahdas Trauki\nsprahdfs.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Es runnaschu/ ka es\nwarru atpubſtees/ es atdarritchu\nfawas Luhpas/ nn athildeſchu.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Es ne kahda Zilweka Wai-\ngu usluhkofchu/ nn ne runna-\nschu kahdami Zilwekam paprab-\ntam.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Jo es ne finnu/ ja es Zil-\nwekam paprahtam runnatu/ ar-\nrig mans Darritajs manni ah-\ntri nehft nemtu.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
